    border-radius: 20px;
    cursor: pointer;
    font-size: 10.5px;
    font-weight: 600;
    letter-spacing: 0.4px;
    transition: border-color 0.12s, color 0.12s, background 0.12s;
    font-family: inherit;
}
.blang-btn:hover { border-color: #6366f1; color: #6366f1; }
.blang-btn.active { background: #6366f1; border-color: #6366f1; color: #fff; }

#banner-copy-btn {
    margin-left: auto;
    background: transparent;
    border: 1px solid #cbd5e1;
    color: #64748b;
    padding: 4px 14px;
    border-radius: 20px;
    cursor: pointer;
    font-size: 11px;
    font-weight: 500;
    display: flex;
    align-items: center;
    gap: 5px;
    transition: border-color 0.12s, color 0.12s, background 0.12s;
    font-family: inherit;
}
#banner-copy-btn:hover { border-color: #6366f1; color: #6366f1; }
#banner-copy-btn.copied { border-color: #16a34a; color: #16a34a; }

#banner-prompt-area {
    flex: 1;
    overflow-y: auto;
    font-size: 11px;
    line-height: 1.62;
    white-space: pre-wrap;
    font-family: 'SF Mono', 'Fira Code', 'Courier New', monospace;
    background: #f8fafc;
    border: 1px solid #e2e8f0;
    border-radius: 6px;
    padding: 10px 14px;
    color: #475569;
    scrollbar-width: thin;
    scrollbar-color: #cbd5e1 transparent;
}
#banner-prompt-area::-webkit-scrollbar { width: 3px; }
#banner-prompt-area::-webkit-scrollbar-thumb { background: #cbd5e1; border-radius: 2px; }

#banner-spacer {
    height: 40px;
    transition: height 0.24s cubic-bezier(0.16,1,0.3,1);
}
#recruiter-banner:hover + #banner-spacer { height: calc(40px + 33vh); }
